class OrderComparator implements Comparator<Order> {
    @Override
    public int compare(Order o1, Order o2) {
        // Custom comparison logic here
        if ("high".equals(o1.getPriority()) && "rush".equals(o2.getPriority())) {
            return 0; // Equal priority
        } else if ("high".equals(o1.getPriority())) {
            return -1; // High priority comes first
        } else if ("rush".equals(o2.getPriority())) {
            return 1; // Rush priority comes second
        }
        return 0; // Default case, should not happen
    }
}

public class Main {
    public static void main(String[] args) {
        List<Order> orders = List.of(
            new Order("high"),
            new Order("rush"),
            new Order("low")
        );

        List<Order> filteredOrders = orders.stream()
            .filter(o -> "high".equals(o.getPriority()) || "rush".equals(o.getPriority()))
            .sorted(new OrderComparator())
            .collect(Collectors.toList());

        // Print the filtered orders
        filteredOrders.forEach(System.out::println);
    }
}
